body {
  /* Ensure you are using a variable font that includes an 'opsz' (optical size) axis */
  font-family: "Inter var", sans-serif;
  font-optical-sizing: auto; /* Activates optical sizing based on font-size */
}

h1 {
  font-size: 3.5em; /* Larger text will get optical adjustments for display sizes */
  line-height: 1.1;
}

p {
  font-size: 1em; /* Smaller text will get optical adjustments for text sizes */
  line-height: 1.6;
}

/* You can disable it if a specific design requires it */
.no-optical-sizing {
  font-optical-sizing: none;
}
